def timed(func):
    def wrapper(*args, **kwargs):
        # works for ANY func signature
        return func(*args, **kwargs)
    return wrapper

@timed
def greet(name, greeting="Hi"):
    return f"{greeting}, {name}"

print(greet("Ada", greeting="Hello"))  # Hello, Ada

def point(x, y, z):
    return (x, y, z)

coords = [1, 2, 3]
print(point(*coords))        # (1, 2, 3)

opts = {"x": 1, "y": 2, "z": 3}
print(point(**opts))         # (1, 2, 3)

def save(data, *, overwrite=False):
    print(data, overwrite)

save("file", overwrite=True)   # ok: passed by name

try:
    save("file", True)         # TypeError
except TypeError as e:
    print("error:", e)         # takes 1 positional arg

def average(*nums):
    if not nums:
        return 0
    return sum(nums) / len(nums)

print(average(4, 8))          # 6.0
print(average(1, 2, 3, 4, 5)) # 3.0
print(average())              # 0

import functools

def logged(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f"calling {func.__name__}")
        return func(*args, **kwargs)   # forward intact
    return wrapper

@logged
def multiply(a, b):
    return a * b

print(multiply(3, 5))   # calling multiply  ->  15

def make_request(url, **options):
    config = {"method": "GET", "timeout": 30}
    config.update(options)        # caller overrides defaults
    return config

print(make_request("/api"))
# {'method': 'GET', 'timeout': 30}
print(make_request("/api", method="POST", timeout=5))
# {'method': 'POST', 'timeout': 5}

def connect(host, port, user):
    return f"{user}@{host}:{port}"

settings = {"host": "db", "port": 5432, "user": "ada"}
print(connect(**settings))     # ada@db:5432

args = ["db", 5432, "ada"]
print(connect(*args))          # ada@db:5432

class Animal:
    def __init__(self, name):
        self.name = name

class Dog(Animal):
    def __init__(self, breed, **kwargs):
        super().__init__(**kwargs)   # forward name up
        self.breed = breed

d = Dog(breed="corgi", name="Rex")
print(d.name, d.breed)   # Rex corgi

def wrapper(func):
    def inner(*args, **kwargs):
        # WRONG: passes a tuple and a dict
        # return func(args, kwargs)
        return func(*args, **kwargs)   # RIGHT
    return inner

@wrapper
def add(a, b):
    return a + b

print(add(2, 3))   # 5

def greet(name, msg):
    return f"{msg}, {name}"

extra = {"name": "Ada", "msg": "Hi"}

try:
    # 'Bob' fills name, then **extra fills name again
    print(greet("Bob", **extra))
except TypeError as e:
    print("error:", e)   # multiple values for 'name'

def loose(**kwargs):
    timeout = kwargs.get("timeout", 30)
    return timeout

print(loose(timeoutt=5))   # 30  <- typo ignored!

def strict(*, timeout=30):
    return timeout

try:
    strict(timeoutt=5)     # TypeError: caught
except TypeError as e:
    print("error:", e)
